export default class View{static cache=new Map;static async load(t){const e=`/views/${t}.html`;if(this.cache.has(e))return this.cache.get(e);try{const t=await fetch(e);if(!t.ok)throw new Error(`Could not load template: ${e}`);const a=await t.text();return this.cache.set(e,a),a}catch(e){return console.error("View Loader Error:",e),`<div class="error">Template ${t} not found.</div>`}}}